    let count = 0;

    // A subarray nums[i...j] is "good" if (nums[i] | ... | nums[j]) is present in {nums[i], ..., nums[j]}

    // The condition is: OR(nums[i]...nums[j]) == exists_in_subarray(nums[i]...nums[j])
    // Let OR_val = nums[i] | ... | nums[j].
    // The condition is satisfied if and only if OR_val is equal to some element nums[k] where i <= k <= j.

    // Since OR_val is the bitwise OR of all elements, it must be greater than or equal to every element in the subarray.
    // OR_val >= nums[k] for all k in [i, j].
    // If OR_val = nums[k], then OR_val must equal the smallest element in the subarray whose value equals OR_val.
    // More strongly, if OR_val = nums[k], then all bits set in OR_val must also be set in nums[k].
    // Since OR_val is the OR of all elements, if a bit is set in OR_val, it must be set in at least one element in the subarray.
    // If OR_val = nums[k], it means that for every bit set in OR_val, that bit must be set in nums[k].
    // This implies that for every other element nums[m] (m != k), if nums[m] has a bit set that is NOT set in nums[k],
    // this bit must not be set in OR_val, which is a contradiction unless nums[m] is a submask of nums[k] (nums[m] | nums[k] = nums[k]).

    // A simpler necessary and sufficient condition:
    // OR_val = nums[i] | ... | nums[j].
    // OR_val = nums[k] for some i <= k <= j.
    // This means that for every element nums[m] in the subarray [i, j], nums[m] must be a submask of nums[k] (nums[m] | nums[k] = nums[k]).
    // Why? Because if nums[m] has a bit set that is not set in nums[k], then OR_val will also have that bit set, meaning OR_val != nums[k].

    // Therefore, a subarray nums[i...j] is "good" if and only if there exists an index k in [i, j] such that nums[m] | nums[k] = nums[k] for all m in [i, j].
    // This means nums[k] must be a "superset" (in terms of set bits) of all elements in the subarray.

    // Let's use a dynamic/sliding window approach or iterate over all possible right endpoints j, and count valid left endpoints i <= j.

    // For a fixed right endpoint j, we want to find the number of starting points i <= j such that the subarray nums[i...j] is good.

    // For a fixed j, we iterate backwards for i from j down to 0.
    // As i decreases, the OR sum OR_i_j = nums[i] | OR_{i+1}_j is non-decreasing (in terms of set bits).
    // We need to check if OR_i_j is present in nums[i...j].

    // Since the number of distinct OR values starting at j and moving left is at most log(max(nums)), we can track them.

    // Let's iterate over all possible pairs (i, j) and check the condition, but optimize the check.

    for (let j = 0; j < n; j++) {
        let currentOR = 0;
        let seenElements = new Set();

        for (let i = j; i >= 0; i--) {
            // Update OR sum for subarray nums[i...j]
            currentOR |= nums[i];

            // Update seen elements set
            seenElements.add(nums[i]);

            // Check if currentOR is present in the subarray nums[i...j]
            // This is equivalent to checking if currentOR is in seenElements.
            if (seenElements.has(currentOR)) {
                count++;
            }
        }
    }

    return count;
}

